INSERT INTO `query_log` VALUES (1,'查询老龄化最严重的10个区域','SELECT * FROM population ORDER BY age_65_plus DESC LIMIT 10','1252626755@qq.com','2026-07-17 10:25:31'),(2,'','SELECT COUNT(*) as total FROM population','','2026-07-17 10:26:03'),(3,'','SELECT * FROM policy_record LIMIT 5','','2026-07-17 10:26:03'),(4,'','SELECT * FROM social_security LIMIT 5','','2026-07-17 10:26:03'),(5,'','SELECT * FROM population LIMIT 5','','2026-07-17 10:26:03'),(6,'','SELECT id, age_0_14, age_15_64, age_65_plus FROM population LIMIT 10','','2026-07-17 10:26:07'),(7,'','SELECT id, birth_rate, death_rate, life_expectancy FROM population LIMIT 20','','2026-07-17 10:26:11'),(8,'','SELECT id, age_0_14, age_15_64, age_65_plus FROM population LIMIT 20','','2026-07-17 10:26:16'),(9,'查询人口最多的区域','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) AS total_population FROM population ORDER BY total_population DESC LIMIT 1','1252626755@qq.com','2026-07-17 10:43:50'),(10,'查询人口最多的区域','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) as total_population FROM population ORDER BY total_population DESC LIMIT 1','1252626755@qq.com','2026-07-17 10:43:55'),(11,'改成只看前3个','SELECT id, age_65_plus FROM population ORDER BY age_65_plus DESC LIMIT 3','1252626755@qq.com','2026-07-17 10:46:16'),(12,'改成只看前3个','SELECT id, age_65_plus FROM population ORDER BY age_65_plus DESC LIMIT 3','1252626755@qq.com','2026-07-17 10:46:40'),(13,'再关联社保基金余额看看','SELECT p.id, p.age_65_plus, s.fund_balance FROM population p JOIN social_security s ON p.id = s.population_id ORDER BY p.age_65_plus DESC LIMIT 3','1252626755@qq.com','2026-07-17 10:46:56'),(14,'查询人口最多的5个区域','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) AS total_population FROM population ORDER BY total_population DESC LIMIT 5','1252626755@qq.com','2026-07-17 10:47:48'),(15,'查询人口最多的5个区域','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) AS total_population FROM population ORDER BY total_population DESC LIMIT 5','1252626755@qq.com','2026-07-17 10:47:54'),(16,'只看前2个就行','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) AS total_population FROM population ORDER BY total_population DESC LIMIT 2','1252626755@qq.com','2026-07-17 10:48:08'),(17,'再加上社保基金余额','SELECT p.id, (p.age_0_14 + p.age_15_64 + p.age_65_plus) AS total_population, s.fund_balance FROM population p JOIN social_security s ON p.id = s.population_id ORDER BY total_population DESC LIMIT 2','1252626755@qq.com','2026-07-17 10:48:19'),(18,'查询老龄化最严重的五个区域','SELECT id, age_65_plus FROM population ORDER BY age_65_plus DESC LIMIT 5','1252626755@qq.com','2026-07-17 10:48:31'),(19,'只看前两个就行','SELECT id, age_65_plus FROM population ORDER BY age_65_plus DESC LIMIT 2','1252626755@qq.com','2026-07-17 10:48:54'),(20,'','SELECT age_0_14, age_15_64, age_65_plus FROM population','','2026-07-17 10:50:17'),(21,'','SELECT fund_balance FROM social_security','','2026-07-17 10:50:17'),(22,'','SELECT adjustment_action, COUNT(*) as count FROM policy_record GROUP BY adjustment_action','','2026-07-17 10:50:17'),(23,'','SELECT SUM(age_0_14) as total_0_14, SUM(age_15_64) as total_15_64, SUM(age_65_plus) as total_65_plus FROM population','','2026-07-17 10:50:30'),(24,'','SELECT \n  CASE \n    WHEN fund_balance < 900000000 THEN \'低于9亿\'\n    WHEN fund_balance < 950000000 THEN \'9-9.5亿\'\n    WHEN fund_balance < 1000000000 THEN \'9.5-10亿\'\n    WHEN fund_balance < 1050000000 THEN \'10-10.5亿\'\n    WHEN fund_balance < 1100000000 THEN \'10.5-11亿\'\n    ELSE \'高于11亿\'\n  END as range,\n  COUNT(*) as count\nFROM social_security\nGROUP BY range\nORDER BY range','','2026-07-17 10:50:30'),(25,'','SELECT \n  CASE \n    WHEN fund_balance < 900000000 THEN \'低于9亿\'\n    WHEN fund_balance < 950000000 THEN \'9-9.5亿\'\n    WHEN fund_balance < 1000000000 THEN \'9.5-10亿\'\n    WHEN fund_balance < 1050000000 THEN \'10-10.5亿\'\n    WHEN fund_balance < 1100000000 THEN \'10.5-11亿\'\n    ELSE \'高于11亿\'\n  END as balance_range,\n  COUNT(*) as cnt\nFROM social_security\nGROUP BY balance_range\nORDER BY balance_range','','2026-07-17 10:50:38'),(26,'','SELECT p.id, p.age_0_14, p.age_15_64, p.age_65_plus, s.contribution_rate, s.fund_balance FROM population p JOIN social_security s ON p.id = s.population_id ORDER BY p.id;','','2026-07-17 10:51:32'),(27,'','SELECT id, population_id, fund_balance FROM social_security','','2026-07-17 10:55:54'),(28,'','SELECT policy_flag, COUNT(*) as count FROM policy_record GROUP BY policy_flag','','2026-07-17 10:55:54'),(29,'','SELECT id, age_0_14, age_15_64, age_65_plus FROM population','','2026-07-17 10:55:54'),(30,'','SELECT p.id, s.fund_balance FROM population p JOIN social_security s ON p.id = s.population_id','','2026-07-17 11:00:19'),(31,'','SELECT adjustment_action, COUNT(*) as count FROM policy_record GROUP BY adjustment_action','','2026-07-17 11:00:19'),(32,'','SELECT id, age_0_14, age_15_64, age_65_plus FROM population','','2026-07-17 11:00:19'),(33,'','SELECT id, fund_balance FROM social_security','','2026-07-17 11:00:38'),(34,'','SELECT age_0_14, age_15_64, age_65_plus FROM population','','2026-07-17 11:00:38'),(35,'','SELECT adjustment_action, COUNT(*) as count FROM policy_record GROUP BY adjustment_action','','2026-07-17 11:00:38'),(36,'查询人口最多的3个区域','SELECT id, age_0_14, age_15_64, age_65_plus, (age_0_14 + age_15_64 + age_65_plus) AS total_population FROM population ORDER BY total_population DESC LIMIT 3','1252626755@qq.com','2026-07-17 11:16:36');
